"""
Django Q objects for building complex query expressions.
"""

import operator
from functools import reduce


class Q:
    """
    Encapsulate filters as objects that can then be combined logically
    using `&` (AND) and `|` (OR) operators.
    """

    AND = "AND"
    OR = "OR"
    XOR = "XOR"
    conditional = True

    def __init__(self, *args, _connector=None, _negated=False, **kwargs):
        self.children = list(args) + sorted(kwargs.items())
        self.connector = _connector or self.AND
        self.negated = _negated

    def __and__(self, other):
        return self._combine(other, self.AND)

    def __or__(self, other):
        return self._combine(other, self.OR)

    def __xor__(self, other):
        return self._combine(other, self.XOR)

    def __invert__(self):
        obj = self.copy()
        obj.negated = not self.negated
        return obj

    def __repr__(self):
        template = "(NOT (%s: %s))" if self.negated else "(%s: %s)"
        return template % (self.connector, ", ".join(str(c) for c in self.children))

    def __bool__(self):
        return bool(self.children)

    def __len__(self):
        return len(self.children)

    def _combine(self, other, conn):
        """Combine this Q object with another using the given connector."""
        if not isinstance(other, Q):
            raise TypeError(other)

        if not self:
            return other.copy()
        if not other:
            return self.copy()

        obj = self.__class__()
        obj.connector = conn
        obj.add(self, conn)
        obj.add(other, conn)
        return obj

    def add(self, node, conn):
        """Add a node to the Q object, respecting connector types."""
        if node.connector == conn and not node.negated:
            self.children.extend(node.children)
        else:
            self.children.append(node)

    def copy(self):
        """Return a deep copy of this Q object."""
        obj = self.__class__(_connector=self.connector, _negated=self.negated)
        obj.children = self.children[:]
        return obj

    def resolve_expression(self, query, allow_joins=True, reuse=None, summarize=False):
        """Resolve the Q object into a WhereNode for the query compiler."""
        clause, joins = query._add_q(self, reuse, allow_joins=allow_joins, split_subq=False)
        query.promote_joins(joins)
        return clause

    @classmethod
    def create(cls, children, connector=AND, negated=False):
        """Create a new Q instance from a list of children."""
        obj = cls(_connector=connector, _negated=negated)
        obj.children = children
        return obj

    @classmethod
    def combine_queries(cls, queries, connector=AND):
        """Combine multiple Q objects with the given connector."""
        if not queries:
            return cls()
        return reduce(operator.and_ if connector == cls.AND else operator.or_, queries)

"""
Django-style SQL query compiler infrastructure.
"""


class SQLQuery:
    """Represent a structured SQL query."""

    compiler = "SQLCompiler"
    _db = None

    def __init__(self, model=None, where=None, alias_map=None):
        self.model = model
        self.where = where or WhereNode()
        self.alias_map = alias_map or {}
        self.tables = []
        self.select = []
        self.group_by = None
        self.order_by = []
        self.distinct = False
        self.distinct_fields = []
        self.standard_ordering = True
        self.select_related = False
        self.max_depth = 5
        self.values_select = ()
        self.annotation_select_mask = None
        self.extra_select_mask = None
        self._extra = {}
        self._annotations = {}

    def as_sql(self, compiler=None, connection=None):
        """Return the query as an SQL string and parameters."""
        compiler = compiler or self.get_compiler(connection=connection)
        return compiler.as_sql()

    def get_compiler(self, using=None, connection=None, elide_empty=True):
        """Return a compiler instance for this query."""
        if using is None and connection is None:
            raise ValueError("Need either using or connection")
        if using:
            from django.db import connections
            connection = connections[using]
        return connection.ops.compiler(self.compiler)(
            self, connection, using, elide_empty=elide_empty
        )

    def add_filter(self, filter_lhs, filter_rhs, connector="AND", negate=False):
        """Add a single filter to the query."""
        clause = self._build_lookup(filter_lhs, filter_rhs)
        if negate:
            clause.negate()
        self.where.add(clause, connector)

    def add_ordering(self, *ordering):
        """Add items from the 'ordering' sequence to the query's order by."""
        errors = []
        for item in ordering:
            if isinstance(item, str) and item == "?":
                continue
            if hasattr(item, "resolve_expression"):
                continue
            if isinstance(item, str):
                if item.startswith("-"):
                    item = item[1:]
                if item in ("pk",):
                    continue
                if not self._check_field_name(item):
                    errors.append(item)
        if errors:
            raise FieldError("Invalid order_by arguments: %s" % errors)
        self.order_by.extend(ordering)

    def clone(self):
        """Return a copy of the current query."""
        obj = self.__class__(model=self.model)
        obj.where = self.where.clone()
        obj.alias_map = self.alias_map.copy()
        obj.tables = self.tables[:]
        obj.select = self.select[:]
        obj.group_by = self.group_by
        obj.order_by = self.order_by[:]
        obj.distinct = self.distinct
        obj.distinct_fields = self.distinct_fields[:]
        obj.standard_ordering = self.standard_ordering
        obj.select_related = self.select_related
        obj.max_depth = self.max_depth
        obj.values_select = self.values_select
        obj._extra = self._extra.copy()
        obj._annotations = self._annotations.copy()
        return obj

    def _build_lookup(self, lhs, rhs):
        """Build a WhereNode from a filter expression."""
        return WhereNode(children=[(lhs, rhs)])

    def _check_field_name(self, name):
        """Check if a field name is valid for the model."""
        if self.model is None:
            return True
        return hasattr(self.model, name) or name in self.annotation_select_mask or {}


class WhereNode:
    """Represent an SQL WHERE clause."""

    default_connector = "AND"

    def __init__(self, children=None, connector=None, negated=False):
        self.children = children or []
        self.connector = connector or self.default_connector
        self.negated = negated

    def add(self, node, connector):
        if self.connector == connector:
            self.children.append(node)
        else:
            new_node = WhereNode(children=self.children[:], connector=self.connector)
            self.children = [new_node, node]
            self.connector = connector

    def negate(self):
        self.negated = not self.negated

    def clone(self):
        obj = WhereNode(
            children=[c.clone() if hasattr(c, "clone") else c for c in self.children],
            connector=self.connector,
            negated=self.negated,
        )
        return obj


class FieldError(Exception):
    """Raised when a field lookup encounters a problem."""
    pass

    Look up an object with the given kwargs, creating one if necessary.
    Return a tuple of (object, created), where created is a boolean
    specifying whether an object was created.
    """
    # The get() needs to be targeted at the write database in order
    # to avoid potential transaction consistency problems.
    self._for_write = True
    try:
        return self.get(**kwargs), False
    except self.model.DoesNotExist:
        params = self._extract_model_params(defaults, **kwargs)
        # Try to create an object using passed params.
        try:
            with transaction.atomic(using=self.db):
                params = dict(resolve_callables(params))
                return self.create(**params), True
        except IntegrityError:
            try:
                return self.get(**kwargs), False
            except self.model.DoesNotExist:
                pass
            raise

get_or_create.alters_data = True

async def aget_or_create(self, defaults=None, **kwargs):
    return await sync_to_async(self.get_or_create)(
        defaults=defaults,
        **kwargs,
    )

aget_or_create.alters_data = True

def update_or_create(self, defaults=None, create_defaults=None, **kwargs):
    """
    Look up an object with the given kwargs, updating one with defaults
    if it exists, otherwise create a new one. Optionally, an object can
    be created with different values than defaults by using
    create_defaults.
    Return a tuple (object, created), where created is a boolean
    specifying whether an object was created.
    """
    update_defaults = defaults or {}
    if create_defaults is None:
        create_defaults = update_defaults

    self._for_write = True
    with transaction.atomic(using=self.db):
        # Lock the row so that a concurrent update is blocked until
        # update_or_create() has performed its save.
        obj, created = self.select_for_update().get_or_create(
            create_defaults, **kwargs
        )
        if created:
            return obj, created
        for k, v in resolve_callables(update_defaults):
            setattr(obj, k, v)

        update_fields = set(update_defaults)
        concrete_field_names = self.model._meta._non_pk_concrete_field_names
        # update_fields does not support non-concrete fields.
        if concrete_field_names.issuperset(update_fields):
            # Add fields which are set on pre_save(), e.g. auto_now fields.
            # This is to maintain backward compatibility as these fields
            # are not updated unless explicitly specified in the
            # update_fields list.
            pk_fields = self.model._meta.pk_fields
            for field in self.model._meta.local_concrete_fields:
                if not (
                    field in pk_fields or field.__class__.pre_save is Field.pre_save
                ):
                    update_fields.add(field.name)
                    if field.name != field.attname:
                        update_fields.add(field.attname)
            obj.save(using=self.db, update_fields=update_fields)
        else:
            obj.save(using=self.db)
    return obj, False

update_or_create.alters_data = True

