    field_names = {f: False for f in fields if not hasattr(f, "resolve_expression")}
    _fields = []
    expressions = {}
    counter = 1
    for field in fields:
        field_name = field
        expression = None
        if hasattr(field, "resolve_expression"):
            field_name = getattr(
                field, "default_alias", field.__class__.__name__.lower()
            )
            expression = field
            # For backward compatibility reasons expressions are always
            # prefixed with the counter even if their default alias doesn't
            # collide with field names. Changing this logic could break
            # some usage of named=True.
            seen = True
        elif seen := field_names[field_name]:
            expression = F(field_name)
        if seen:
            field_name_prefix = field_name
            while (field_name := f"{field_name_prefix}{counter}") in field_names:
                counter += 1
        if expression is not None:
            expressions[field_name] = expression
        field_names[field_name] = True
        _fields.append(field_name)

    clone = self._values(*_fields, **expressions)
    clone._iterable_class = (
        NamedValuesListIterable
        if named
        else FlatValuesListIterable if flat else ValuesListIterable
    )
    return clone

def dates(self, field_name, kind, order="ASC"):
    """
    Return a list of date objects representing all available dates for
    the given field_name, scoped to 'kind'.
    """
    if kind not in ("year", "month", "week", "day"):
        raise ValueError("'kind' must be one of 'year', 'month', 'week', or 'day'.")
    if order not in ("ASC", "DESC"):
        raise ValueError("'order' must be either 'ASC' or 'DESC'.")
    return (
        self.annotate(
            datefield=Trunc(field_name, kind, output_field=DateField()),
            plain_field=F(field_name),
        )
        .values_list("datefield", flat=True)
        .distinct()
        .filter(plain_field__isnull=False)
        .order_by(("-" if order == "DESC" else "") + "datefield")
    )

def datetimes(self, field_name, kind, order="ASC", tzinfo=None):
    """
    Return a list of datetime objects representing all available
    datetimes for the given field_name, scoped to 'kind'.
    """
    if kind not in ("year", "month", "week", "day", "hour", "minute", "second"):
        raise ValueError(
            "'kind' must be one of 'year', 'month', 'week', 'day', "
            "'hour', 'minute', or 'second'."
        )
    if order not in ("ASC", "DESC"):
        raise ValueError("'order' must be either 'ASC' or 'DESC'.")
    if settings.USE_TZ:
        if tzinfo is None:
            tzinfo = timezone.get_current_timezone()
    else:
        tzinfo = None
    return (
        self.annotate(
            datetimefield=Trunc(
                field_name,
                kind,
                output_field=DateTimeField(),
                tzinfo=tzinfo,
            ),
            plain_field=F(field_name),
        )
        .values_list("datetimefield", flat=True)
        .distinct()
        .filter(plain_field__isnull=False)
        .order_by(("-" if order == "DESC" else "") + "datetimefield")
    )

def none(self):
    """Return an empty QuerySet."""
    clone = self._chain()
    clone.query.set_empty()
    return clone

##################################################################
# PUBLIC METHODS THAT ALTER ATTRIBUTES AND RETURN A NEW QUERYSET #
##################################################################

def all(self):
    """
    Return a new QuerySet that is a copy of the current one. This allows a
    QuerySet to proxy for a model manager in some cases.
    """
    return self._chain()

def filter(self, *args, **kwargs):
    """
    Return a new QuerySet instance with the args ANDed to the existing
    set.
    """
    self._not_support_combined_queries("filter")
    return self._filter_or_exclude(False, args, kwargs)

def exclude(self, *args, **kwargs):
    """
    Return a new QuerySet instance with NOT (args) ANDed to the existing
    set.
    """
    self._not_support_combined_queries("exclude")
    return self._filter_or_exclude(True, args, kwargs)

def _filter_or_exclude(self, negate, args, kwargs):
    if (args or kwargs) and self.query.is_sliced:
        raise TypeError("Cannot filter a query once a slice has been taken.")
    clone = self._chain()
    if self._defer_next_filter:
        self._defer_next_filter = False
        clone._deferred_filter = negate, args, kwargs
    else:
        clone._filter_or_exclude_inplace(negate, args, kwargs)
    return clone

def _filter_or_exclude_inplace(self, negate, args, kwargs):
    if invalid_kwargs := PROHIBITED_FILTER_KWARGS.intersection(kwargs):
        invalid_kwargs_str = ", ".join(f"'{k}'" for k in sorted(invalid_kwargs))
        raise TypeError(f"The following kwargs are invalid: {invalid_kwargs_str}")
    if negate:
        self._query.add_q(~Q(*args, **kwargs))
    else:
        self._query.add_q(Q(*args, **kwargs))

def complex_filter(self, filter_obj):
    """
    Return a new QuerySet instance with filter_obj added to the filters.

    filter_obj can be a Q object or a dictionary of keyword lookup
    arguments.

    This exists to support framework features such as 'limit_choices_to',
    and usually it will be more natural to use other methods.
    """
    if isinstance(filter_obj, Q):
        clone = self._chain()
        clone.query.add_q(filter_obj)
        return clone
    else:
        return self._filter_or_exclude(False, args=(), kwargs=filter_obj)

def _combinator_query(self, combinator, *other_qs, all=False):
    # Clone the query to inherit the select list and everything
    clone = self._chain()
    # Clear limits and ordering so they can be reapplied
    clone.query.clear_ordering(force=True)
    clone.query.default_ordering = True
    clone.query.clear_limits()
    clone.query.combined_queries = (self.query, *(qs.query for qs in other_qs))
    clone.query.combinator = combinator
    clone.query.combinator_all = all
    return clone

def union(self, *other_qs, all=False):
    # If the query is an EmptyQuerySet, combine all nonempty querysets.
    if isinstance(self, EmptyQuerySet):
        qs = [q for q in other_qs if not isinstance(q, EmptyQuerySet)]
        if not qs:
            return self
        if len(qs) == 1:
            return qs[0]
        return qs[0]._combinator_query("union", *qs[1:], all=all)
    elif not other_qs:
        return self
    return self._combinator_query("union", *other_qs, all=all)

def intersection(self, *other_qs):
    # If any query is an EmptyQuerySet, return it.
    if isinstance(self, EmptyQuerySet):
        return self
    for other in other_qs:
        if isinstance(other, EmptyQuerySet):
            return other
    return self._combinator_query("intersection", *other_qs)

def difference(self, *other_qs):
    # If the query is an EmptyQuerySet, return it.
    if isinstance(self, EmptyQuerySet):
        return self
    return self._combinator_query("difference", *other_qs)

def select_for_update(self, nowait=False, skip_locked=False, of=(), no_key=False):
    """
    Return a new QuerySet instance that will select objects with a
    FOR UPDATE lock.
    """
    if nowait and skip_locked:
        raise ValueError("The nowait option cannot be used with skip_locked.")
    obj = self._chain()
    obj._for_write = True
    obj.query.select_for_update = True
    obj.query.select_for_update_nowait = nowait
    obj.query.select_for_update_skip_locked = skip_locked
    obj.query.select_for_update_of = of
    obj.query.select_for_no_key_update = no_key
    return obj

def select_related(self, *fields):
    """
    Return a new QuerySet instance that will select related objects.

    If fields are specified, they must be ForeignKey fields and only those
    related objects are included in the selection.

    If select_related(None) is called, clear the list.
    """
    self._not_support_combined_queries("select_related")
    if self._fields is not None:
        raise TypeError(
            "Cannot call select_related() after .values() or .values_list()"
        )

    obj = self._chain()
    if fields == (None,):
        obj.query.select_related = False
    elif fields:
        obj.query.add_select_related(fields)
    else:
        obj.query.select_related = True
    return obj

def prefetch_related(self, *lookups):
    """
    Return a new QuerySet instance that will prefetch the specified
    Many-To-One and Many-To-Many related objects when the QuerySet is
    evaluated.

    When prefetch_related() is called more than once, append to the list of
    prefetch lookups. If prefetch_related(None) is called, clear the list.
    """
    self._not_support_combined_queries("prefetch_related")
    clone = self._chain()
    if lookups == (None,):
        clone._prefetch_related_lookups = ()
    else:
        for lookup in lookups:
            if isinstance(lookup, Prefetch):
                lookup = lookup.prefetch_to
            lookup = lookup.split(LOOKUP_SEP, 1)[0]
            if lookup in self.query._filtered_relations:
                raise ValueError(
                    "prefetch_related() is not supported with FilteredRelation."
                )
        clone._prefetch_related_lookups = clone._prefetch_related_lookups + lookups
    return clone

def annotate(self, *args, **kwargs):
    """
    Return a query set in which the returned objects have been annotated
    with extra data or aggregations.
    """
    self._not_support_combined_queries("annotate")
    return self._annotate(args, kwargs, select=True)

def alias(self, *args, **kwargs):
    """
    Return a query set with added aliases for extra data or aggregations.
    """
    self._not_support_combined_queries("alias")
    return self._annotate(args, kwargs, select=False)

def _annotate(self, args, kwargs, select=True):
    self._validate_values_are_expressions(
        args + tuple(kwargs.values()), method_name="annotate"

